// ── IT-Sicherheit (9 Karten — 116x geprüft) ──
final List<CardModel> itsicherheitKarten = [
  CardModel(id: 'itsicherheitKarten-001', question: 'Was sind die Schutzziele der Informationssicherheit?', shortAnswer: 'Vertraulichkeit, Integrität, Verfügbarkeit (CIA) + Authentizität', longAnswer: '• Vertraulichkeit: Informationen nur für Befugte zugänglich\n→ Maßnahme: Verschlüsselung, Zugangskontrolle\n• Integrität: Daten sind vollständig und unverändert\n→ Maßnahme: Hashverfahren, digitale Signaturen\n• Verfügbarkeit: Systeme sind bei Bedarf nutzbar\n→ Maßnahme: Redundanz, Backup, USV\n• Authentizität: Echtheit und Identität sind nachweisbar\n→ Maßnahme: Zertifikate, 2FAMerkhilfe: CIA-Triade', url: '', hashtags: ['#IT-Sicherheit', '#Kryptographie', '#AP1']),
  CardModel(id: 'itsicherheitKarten-002', question: 'Was ist der Unterschied zwischen Virus, Wurm und Trojaner?', shortAnswer: 'Virus = infiziert Dateien; Wurm = verbreitet sich selbst; Trojaner = tarnt sich als nützliche Software', longAnswer: '• Virus: Infiziert ausführbare Dateien, benötigt Wirtsdarei zur Verbreitung\n• Wurm: Verbreitet sich eigenständig über Netzwerke, benötigt keine Wirtsdatei\n• Trojaner: Tarnt sich als harmlose Software, enthält Schadfunktion (Backdoor, Spyware)\n• Ransomware: Verschlüsselt Daten und fordert Lösegeld\n• Rootkit: Verbirgt seine eigene Anwesenheit im System', url: '', hashtags: ['#IT-Sicherheit', '#Kryptographie', '#AP1']),
  CardModel(id: 'itsicherheitKarten-003', question: 'Was ist der Unterschied zwischen symmetrischer und asymmetrischer Verschlüsselung?', shortAnswer: 'Symmetrisch = gleicher Schlüssel zum Ver- und Entschlüsseln; Asymmetrisch = öffentlicher/privater Schlüssel', longAnswer: '• Symmetrische\nVerschlüsselung: Gleicher Schlüssel für Ver- und Entschlüsselung\n→ Schnell, aber Schlüsselaustausch ist Problem\nAlgorithmen: AES, DES\n• Asymmetrische\nVerschlüsselung: Schlüsselpaar (Public Key + Private Key)\n→ Sicherer Schlüsselaustausch, aber langsamer\nAlgorithmen: RSA, ECCIn der\nPraxis: Hybrid (TLS): Asymmetrisch für Schlüsselaustausch, dann symmetrisch für Daten', url: '', hashtags: ['#IT-Sicherheit', '#Kryptographie', '#AP1']),
  CardModel(id: 'itsicherheitKarten-004', question: 'Was ist BSI IT-Grundschutz?', shortAnswer: 'Methodik des BSI zur systematischen Absicherung von IT-Systemen auf Basis von Schutzbedarfsanalyse', longAnswer: 'BSI IT-Grundschutz\nVorgehen:\n• Schutzbedarfsanalyse: Welche Systeme/Daten schützenswert?\n• Schutzbedarf festlegen: Normal, Hoch, Sehr hoch\n• Grundschutz-Bausteine: Vorgefertigte Maßnahmen aus IT-Grundschutzkompendium\n• Sicherheitskonzept: Maßnahmen umsetzen und dokumentieren\nMaßnahmen: technisch (Firewall, Verschlüsselung), organisatorisch (Richtlinien), personell (Schulungen)', url: '', hashtags: ['#IT-Sicherheit', '#Kryptographie', '#AP1']),
  CardModel(id: 'itsicherheitKarten-005', question: 'Was sind Backup-Strategien (Voll, Inkrementell, Differenziell)?', shortAnswer: 'Vollbackup = alles; Inkrementell = nur Änderungen seit letztem Backup; Differenziell = seit letztem Vollbackup', longAnswer: '• Vollbackup: Kopiert ALLE Daten\n→ Einfache Wiederherstellung, aber viel Speicher und Zeit\n• Inkrementelles\nBackup: Nur Änderungen seit dem LETZTEN Backup (egal ob voll oder inkrementell)\n→ Schnell, wenig Speicher; Restore benötigt alle Inkremente\n• Differenzielles\nBackup: Alle Änderungen seit dem LETZTEN VOLLBACKUP\n→ Kompromiss; Restore benötigt nur Vollbackup + letztes differentielles\nGenerationenprinzip: Großvater (monatlich) → Vater (wöchentlich) → Sohn (täglich)', url: '', hashtags: ['#IT-Sicherheit', '#Kryptographie', '#AP1']),
  CardModel(id: 'itsicherheitKarten-006', question: 'Was ist 2FA (Zwei-Faktor-Authentifizierung)?', shortAnswer: 'Kombination aus zwei verschiedenen Faktoren: Wissen, Besitz oder Biometrie', longAnswer: 'Authentifizierungsfaktoren:\n• Wissen: Passwort, PIN, Sicherheitsfrage\n• Besitz: Hardware-Token, Smartphone-App (z.B. Google Authenticator), Smartcard\n• Biometrie: Fingerabdruck, Gesichtserkennung, Retinascan2FA = zwei verschiedene Faktoren kombinieren\nBeispiel: Passwort (Wissen) + SMS-Code (Besitz)\nVorteil: Gestohlenes Passwort allein reicht nicht aus.', url: '', hashtags: ['#IT-Sicherheit', '#Kryptographie', '#AP1']),
  CardModel(id: 'itsicherheitKarten-007', question: 'Was ist Phishing und wie erkennt man es?', shortAnswer: 'Betrügerische E-Mails/Websites, die zur Eingabe von Zugangsdaten verleiten', longAnswer: 'Merkmale von\nPhishing:\n• Absenderadresse sieht ähnlich aus (z.B. amazon-support@gmail.com)\n• Dringlichkeit: \'Ihr Konto wird gesperrt!\'\n• Link führt zu gefälschter Website (URL prüfen!)\n• Schlechte Grammatik/Rechtschreibung\n• Unerwartete AnhängeÄhnliche\nAngriffe:\n• Spear-Phishing: Gezielt auf eine Person/Organisation\n• Spoofing: Gefälschte Absenderadresse\n• Man-in-the-Middle: Angreifer sitzt zwischen zwei Kommunikationspartnern', url: '', hashtags: ['#IT-Sicherheit', '#Kryptographie', '#AP1']),
  CardModel(id: 'itsicherheitKarten-008', question: 'Was ist eine DMZ (demilitarisierte Zone)?', shortAnswer: 'Netzwerksegment zwischen Internet und internem Netz für öffentlich zugängliche Dienste', longAnswer: 'DMZ-Aufbau:\n• Zwischen zwei Firewalls (extern + intern) platziert\n• Enthält öffentlich zugängliche\nServer: Webserver, Mailserver, DNS\n• Internes Netz ist durch zweite Firewall geschützt\nVorteil: Wenn ein DMZ-Server kompromittiert wird, kann der Angreifer nicht direkt ins interne Netz\nPort-Forwarding: Eingehende Verbindungen von außen auf DMZ-Server weiterleiten', url: '', hashtags: ['#IT-Sicherheit', '#Kryptographie', '#AP1']),
  CardModel(id: 'itsicherheitKarten-009', question: 'Was ist WLAN-Sicherheit (WEP, WPA, WPA2, WPA3)?', shortAnswer: 'WEP = unsicher (veraltet); WPA2 = Standard; WPA3 = aktuell sicherste Option', longAnswer: 'StandardVerschlüsselungSicherheitWEPRC4❌ Unsicher (2001 geknackt)WPATKIP⚠️ VeraltetWPA2AES/CCMP✅ StandardWPA3AES/SAE✅✅ Aktuell sichersteEnterprise-Modus: Authentifizierung über RADIUS-Server statt Pre-Shared-Key', url: '', hashtags: ['#IT-Sicherheit', '#Kryptographie', '#AP1']),
];

// ── Projektmanagement (11 Karten — 113x geprüft) ──
