// ── Softwareentwicklung (5 Karten — 107x geprüft) ──
final List<CardModel> softwareentwicklungKarten = [
  CardModel(id: 'softwareentwicklungKarten-001', question: 'Was ist der Unterschied zwischen Compiler und Interpreter?', shortAnswer: 'Compiler = übersetzt gesamten Code vorab; Interpreter = führt Zeile für Zeile aus', longAnswer: '• Compiler: Übersetzt gesamten Quellcode in Maschinencode (einmalig vor Ausführung)\n→ Schnelle Ausführung, Fehler erst nach Kompilierung erkennbar\nBeispiele: C, C++, Java (teilweise)\n• Interpreter: Liest und führt Quellcode Zeile für Zeile aus\n→ Langsamer, aber flexibel, Fehler sofort erkennbar\nBeispiele: Python, JavaScript, PHPJava: Kompiliert zu Bytecode\n→ JVM interpretiert\n→ Plattformunabhängig', url: '', hashtags: ['#Softwareentwicklung', '#UML', '#AP1']),
  CardModel(id: 'softwareentwicklungKarten-002', question: 'Was sind die wichtigsten Datentypen in der Programmierung?', shortAnswer: 'int, float, double, boolean, char, String – Basisdatentypen in den meisten Sprachen', longAnswer: 'Primitive\nDatentypen:\n• byte: 8 Bit, –128 bis 127\n• short: 16 Bit, ca. –32.000 bis 32.000\n• int: 32 Bit, ca. –2 Mrd. bis 2 Mrd.\n• long: 64 Bit, sehr große Ganzzahlen\n• float: 32 Bit Gleitkommazahl\n• double: 64 Bit Gleitkommazahl (präziser)\n• boolean: true/false\n• char: einzelnes ZeichenString ist kein primitiver Typ, sondern eine Klasse.', url: '', hashtags: ['#Softwareentwicklung', '#UML', '#AP1']),
  CardModel(id: 'softwareentwicklungKarten-003', question: 'Was ist der Unterschied zwischen kopfgesteuerten und fußgesteuerten Schleifen?', shortAnswer: 'Kopfgesteuert = Bedingung vor Ausführung geprüft; Fußgesteuert = mindestens einmal ausgeführt', longAnswer: '• Kopfgesteuert (while): Bedingung wird VOR dem ersten Durchlauf geprüft\n→ Schleife wird ggf. kein einziges Mal ausgeführt\n• Fußgesteuert (do...while): Bedingung wird NACH dem ersten Durchlauf geprüft\n→ Schleife wird MINDESTENS einmal ausgeführtBeispiel do-while:\ndo { Aktion } while (Bedingung);', url: '', hashtags: ['#Softwareentwicklung', '#UML', '#AP1']),
  CardModel(id: 'softwareentwicklungKarten-004', question: 'Was sind UML-Diagrammtypen und wofür werden sie genutzt?', shortAnswer: 'Use Case, Klassendiagramm, Aktivitätsdiagramm – wichtigste UML-Typen für AP1', longAnswer: '• Use-Case-Diagramm: Zeigt Akteure und ihre Interaktionen mit dem System (Anforderungen)\n• Klassendiagramm: Zeigt Klassen, Attribute, Methoden und Beziehungen\n• Aktivitätsdiagramm: Zeigt Ablauflogik (wie ein Flussdiagramm)Beziehungen im\nKlassendiagramm:\n• Assoziation: allgemeine Verbindung\n• Aggregation: Teil-Ganzes (Teil kann eigenständig existieren)\n• Komposition: starke Teil-Ganzes-Beziehung (Teil nicht eigenständig)', url: '', hashtags: ['#Softwareentwicklung', '#UML', '#AP1']),
  CardModel(id: 'softwareentwicklungKarten-005', question: 'Was sind funktionale und nicht-funktionale Anforderungen?', shortAnswer: 'Funktional = WAS das System tun soll; Nicht-funktional = WIE GUT es das tun soll', longAnswer: '• Funktionale\nAnforderungen: Konkrete Funktionen des Systems\nBeispiele: \'Nutzer können sich einloggen\', \'System sendet E-Mail-Bestätigung\'\n• Nicht-funktionale\nAnforderungen: Qualitätsmerkmale und Rahmenbedingungen\nBeispiele: Reaktionszeit Nicht-funktionale Anforderungen sind oft entscheidend für die Nutzerzufriedenheit!', url: '', hashtags: ['#Softwareentwicklung', '#UML', '#AP1']),
];

// ── Angebotsvergleich (4 Karten — 77x geprüft) ──
final List<CardModel> angebotsvergleichKarten = [
  CardModel(id: 'angebotsvergleichKarten-001', question: 'Wie funktioniert eine Nutzwertanalyse für einen Angebotsvergleich?', shortAnswer: 'Kriterien gewichten, Alternativen bewerten, gewichtete Punkte addieren, höchster Wert gewinnt', longAnswer: 'Schritte der NWA:\n• Bewertungskriterien festlegen (z.B. Preis, Leistung, Service)\n• Gewichtung vergeben (Summe = 100%)\n• Alternativen pro Kriterium mit Punkten bewerten (z.B. 1\n– 5)\n• Gewichtete Punktzahl = Gewicht × Punkte\n• Gesamtpunktzahl je Alternative summieren\n• Höchste Gesamtpunktzahl = empfohlene Alternative\nWichtig: Begründung der Gewichtung dokumentieren!', url: '', hashtags: ['#Kalkulation', '#Wirtschaft', '#AP1']),
  CardModel(id: 'angebotsvergleichKarten-002', question: 'Was ist der Unterschied zwischen quantitativem und qualitativem Angebotsvergleich?', shortAnswer: 'Quantitativ = Zahlen/Preise vergleichen; Qualitativ = nicht-monetäre Faktoren bewerten', longAnswer: '• Quantitativer\nVergleich: Rein auf Zahlen basierend\n→ Preisvergleich, Lieferzeiten, Stückzahlen\n→ Einfach, objektiv, aber unvollständig\n• Qualitativer\nVergleich: Nicht-messbare Kriterien\n→ Service, Reputation, Kundensupport, Zuverlässigkeit\n→ Subjektiver, schwerer vergleichbarBeste\nMethode: Kombination beider Ansätze\n→ Nutzwertanalyse', url: '', hashtags: ['#Kalkulation', '#Wirtschaft', '#AP1']),
  CardModel(id: 'angebotsvergleichKarten-003', question: 'Was sind die Bestandteile der Handelskalkulation?', shortAnswer: 'Listenpreis → Rabatt → Zielpreis → Skonto → Barpreis → Bezugskosten → Bezugspreis', longAnswer: 'Einkaufskalkulation:\nListeneinkaufspreis\n– Lieferrabatt\n= Zieleinkaufspreis\n– Lieferskonto\n= Bareinkaufspreis\n+ Bezugskosten\n= Bezugspreis (Einstandspreis)\n\nVerkaufskalkulation:\nSelbstkosten\n+ Gewinnaufschlag\n= Barverkaufspreis\n+ Skonto\n= Zielverkaufspreis\n+ Rabatt\n= Listenverkaufspreis', url: '', hashtags: ['#Kalkulation', '#Wirtschaft', '#AP1']),
  CardModel(id: 'angebotsvergleichKarten-004', question: 'Was ist Make-or-Buy und wann wird diese Entscheidung getroffen?', shortAnswer: 'Entscheidung: Eigenentwicklung/Eigenfertigung vs. Fremdbezug/Einkauf von externen Anbietern', longAnswer: 'Make-or-Buy\nKriterien:\n• Make (Eigenfertigung): Bei Kernkompetenzen, wenn Geheimhaltung wichtig, bei langfristigem Bedarf\n• Buy (Fremdbezug): Bei Standardprodukten, wenn Lieferant günstiger, schneller oder besser ist\nEntscheidungsfaktoren: Kosten, Qualität, Know-how, Kapazität, Risiko, Lieferzeit\nBeispiel IT: Individualsoftware (Make) vs. SAP-Standardlösung (Buy)', url: '', hashtags: ['#Kalkulation', '#Wirtschaft', '#AP1']),
