// ── Wirtschaftlichkeit (10 Karten — 72x geprüft) ──
final List<CardModel> wirtschaftlichkeitKarten = [
  CardModel(id: 'wirtschaftlichkeitKarten-001', question: 'Was ist eine Nutzwertanalyse (NWA) und wann wird sie eingesetzt?', shortAnswer: 'Methode zur Entscheidungsfindung bei mehreren Alternativen anhand gewichteter Kriterien', longAnswer: 'Die Nutzwertanalyse (NWA) ist ein Scoring-Modell zur systematischen Bewertung von Alternativen. Sie wird eingesetzt, wenn nicht nur der Preis entscheidet, sondern auch qualitative Faktoren wie Qualität, Service oder Lieferzeit.\n\nVorgehen:\n• Kriterien festlegen\n• Gewichtung in % vergeben (Summe = 100%)\n• Alternativen pro Kriterium bewerten (z.B. 1\n– 10)\n• Gewichtete Punktzahl berechnen: Gewicht × Punkte\n• Summe bilden\n→ höchster Wert gewinnt', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
  CardModel(id: 'wirtschaftlichkeitKarten-002', question: 'Was ist die Amortisationsrechnung?', shortAnswer: 'Berechnung des Zeitraums, bis eine Investition durch Erträge/Einsparungen zurückverdient ist', longAnswer: 'Formel: Amortisationsdauer = Investitionskosten / Ertrag pro Jahr\nBeispiel: Investition 10.000€, jährliche Einsparung 2.500€\n→ Amortisationsdauer = 10.000 / 2.500 = 4 Jahre\n\nJe kürzer die Amortisationsdauer, desto besser für das Unternehmen.\nNachteil: Berücksichtigt keine Zeitwert des Geldes (kein Zinseszins).', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
  CardModel(id: 'wirtschaftlichkeitKarten-003', question: 'Was ist der Deckungsbeitrag?', shortAnswer: 'Deckungsbeitrag = Stückpreis − variable Stückkosten; zeigt den Beitrag zur Fixkostendeckung', longAnswer: 'Formeln:\n• Deckungsbeitrag/Stück: DB = Stückpreis\n– variable Stückkosten\n• Deckungsbeitrag gesamt: DB = Umsatz\n– variable Gesamtkosten\nBedeutung: Zeigt, wie viel jede verkaufte Einheit zur Deckung der Fixkosten beiträgt.\nBeispiel: Preis 50€, var. Kosten 30€ → DB = 20€\n→ Jedes verkaufte Stück \'verdient\' 20€ für Fixkosten und Gewinn.', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
  CardModel(id: 'wirtschaftlichkeitKarten-004', question: 'Was ist der Break-Even-Point?', shortAnswer: 'Der Punkt, bei dem Erlöse und Kosten gleich sind – weder Gewinn noch Verlust', longAnswer: 'Formel: Break-Even-Menge = Fixkosten / Deckungsbeitrag pro Stück\nBeispiel: Fixkosten 10.000€, Stückpreis 50€, variable Kosten 30€\n→ DB = 50\n– 30 = 20€\n→ Break-Even = 10.000 / 20 = 500 Stück\nBedeutung: Ab 500 Stück wird Gewinn erzielt; unter 500 Stück Verlust.\nGrafisch: Schnittpunkt von Erlös- und Gesamtkostenkurve.', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
  CardModel(id: 'wirtschaftlichkeitKarten-005', question: 'Was ist der Unterschied zwischen Effektivität und Effizienz?', shortAnswer: 'Effektivität = die richtigen Dinge tun; Effizienz = die Dinge richtig tun', longAnswer: '• Effektivität: Werden die richtigen Ziele erreicht? (Do the right things!)\nBeispiel: Das richtige Produkt entwickeln\n• Effizienz: Werden die Ziele mit minimalem Aufwand erreicht? (Do things right!)\nBeispiel: Das Produkt ressourcenschonend entwickeln\nMerkhilfe: \'Effektiv = Ergebnis\', \'Effizient = Einsatz\'\nIdeal: Beide gleichzeitig\n– die richtigen Dinge richtig tun.', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
  CardModel(id: 'wirtschaftlichkeitKarten-006', question: 'Was sind fixe und variable Kosten?', shortAnswer: 'Fixe Kosten entstehen unabhängig von der Produktionsmenge; variable Kosten steigen mit der Menge', longAnswer: '• Fixe\nKosten: Bleiben konstant, egal wie viel produziert wird\nBeispiele: Miete, Gehälter, Abschreibungen, Versicherungen\n• Variable\nKosten: Steigen proportional mit der Produktionsmenge\nBeispiele: Rohstoffe, Energiekosten, Verpackung\nFormel: Gesamtkosten = Fixkosten + (variable Stückkosten × Menge)\nWichtig für Break-Even-Analyse und Preiskalkulation!', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
  CardModel(id: 'wirtschaftlichkeitKarten-007', question: 'Was sind die Vor- und Nachteile von Leasing gegenüber Kauf?', shortAnswer: 'Leasing: Liquidität schonen, immer aktuell; Nachteil: teurer, kein Eigentum', longAnswer: 'Leasing VorteileLeasing NachteileLiquidität bleibt erhaltenInsgesamt teurerImmer aktuelle TechnikKein EigentumPlanbare RatenKeine Bilanzaktivierung (bei manchen)Steuerlich absetzbarBindung an LeasinggeberKeine hohe AnfangsinvestitionSchwer kündbar', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
  CardModel(id: 'wirtschaftlichkeitKarten-008', question: 'Wie berechnet man Gewinn und Umsatz?', shortAnswer: 'Umsatz = Absatzmenge × Verkaufspreis; Gewinn = Erlöse − Kosten', longAnswer: 'Wichtige\nFormeln:\n• Umsatz = Absatzmenge × Verkaufspreis\n• Gewinn = Erlöse\n– Kosten (Gesamtkosten)\n• Rentabilität = Gewinn / Kapital × 100%\n• Deckungsbeitrag = Stückpreis\n– variable Stückkosten\n• Amortisation = Investition / Jahresertrag\nBeispiel: Umsatz 100.000€, Kosten 80.000€ → Gewinn = 20.000€', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
  CardModel(id: 'wirtschaftlichkeitKarten-009', question: 'Was ist TCO (Total Cost of Ownership)?', shortAnswer: 'Gesamtkosten eines IT-Systems über die gesamte Nutzungsdauer – inkl. Betrieb und Wartung', longAnswer: 'TCO umfasst alle\nKosten:\n• Anschaffungskosten: Hardware, Software, Lizenzen\n• Betriebskosten: Strom, Personal, Support\n• Wartungskosten: Updates, Reparaturen\n• Schulungskosten: Einarbeitung der Nutzer\n• Entsorgungskosten: Recycling, DatenlöschungTCO hilft beim\nAngebotsvergleich: Ein günstiger Kaufpreis kann hohe Folgekosten verschleiern!', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
  CardModel(id: 'wirtschaftlichkeitKarten-010', question: 'Was ist Rabatt und Skonto?', shortAnswer: 'Rabatt = Preisminderung beim Kauf; Skonto = Preisnachlass bei schneller Zahlung', longAnswer: '• Rabatt: Direkte Preisminderung auf den Listenpreis\n→ z.B. 10% Rabatt auf 1.000€ = 900€ Nettopreis\n• Skonto: Preisnachlass für schnelle Zahlung (z.B. \'2% bei Zahlung in 10 Tagen\')\n→ Skontobetrag = Rechnungsbetrag × Skontosatz\nHandelskalkulation: Listenpreis\n→ abzgl. Rabatt = Zielverkaufspreis\n→ abzgl. Skonto = Barverkaufspreis', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
];

