  CardModel(id: 'multimediaKarten-001', question: 'Was ist der Unterschied zwischen verlustbehafteter und verlustfreier Kompression?', shortAnswer: 'Verlustfrei = original wiederherstellbar; verlustbehaftet = Qualitätsverlust, kleinere Dateien', longAnswer: '• Verlustfreie\nKompression: Originaldaten können vollständig wiederhergestellt werden\nFormate: ZIP, PNG, FLAC, GIF\nMethode: z.B. Huffman-Codierung, RLE\n• Verlustbehaftete\nKompression: Nicht sichtbare/hörbare Daten werden verworfen\nFormate: JPEG, MP3, MP4/H.264\nVorteil: Wesentlich kleinere Dateien\nAnwendungsregel: Archivierung\n→ verlustfrei; Web/Streaming\n→ verlustbehaftet', url: '', hashtags: ['#Multimedia', '#Medien', '#AP1']),
  CardModel(id: 'multimediaKarten-002', question: 'Wie berechnet man die Dateigröße eines Bildes?', shortAnswer: 'Dateigröße = Breite × Höhe × Farbtiefe (in Bit) / 8 (in Byte)', longAnswer: 'Formel: Dateigröße = Breite × Höhe × Farbtiefe / 8\nBeispiel: Bild 1920×1080 Pixel, 24-Bit Farbe (RGB):\n= 1920 × 1080 × 24 / 8\n= 1920 × 1080 × 3 Byte\n= 6.220.800 Byte ≈ 5,9 MB\n\nFarbtiefen: 1 Bit = S/W, 8 Bit = 256 Farben, 24 Bit = 16,7 Mio. Farben (True Color)', url: '', hashtags: ['#Multimedia', '#Medien', '#AP1']),
