// ── Datenschutz (4 Karten — 16x geprüft) ──
final List<CardModel> datenschutzKarten = [
  CardModel(id: 'datenschutzKarten-001', question: 'Was sind die 8 Grundsätze der DSGVO (Art. 5)?', shortAnswer: 'Rechtmäßigkeit, Transparenz, Zweckbindung, Datenminimierung, Richtigkeit, Speicherbegrenzung, Integrität/Vertraulichkeit, Rechenschaftspflicht', longAnswer: 'Die 8 Grundsätze nach DSGVO Art. 5:\n• Rechtmäßigkeit: Verarbeitung braucht Rechtsgrundlage\n• Transparenz: Betroffene müssen informiert werden\n• Zweckbindung: Nur für festgelegte Zwecke nutzen\n• Datenminimierung: Nur notwendige Daten erheben\n• Richtigkeit: Daten müssen aktuell und korrekt sein\n• Speicherbegrenzung: Nicht länger als nötig speichern\n• Integrität & Vertraulichkeit: Sicher verarbeiten\n• Rechenschaftspflicht: Compliance nachweisen können', url: '', hashtags: ['#DSGVO', '#Datenschutz', '#AP1']),
  CardModel(id: 'datenschutzKarten-002', question: 'Was sind die Betroffenenrechte nach DSGVO?', shortAnswer: 'Auskunft, Berichtigung, Löschung, Einschränkung, Widerspruch, Datenübertragbarkeit', longAnswer: 'Betroffenenrechte nach DSGVO:\n• Recht auf\nInformation: Welche Daten werden wie verarbeitet?\n• Recht auf\nAuskunft: Welche Daten hat das Unternehmen über mich?\n• Recht auf\nBerichtigung: Falsche Daten korrigieren lassen\n• Recht auf\nLöschung: \'Recht auf Vergessenwerden\'\n• Recht auf\nEinschränkung: Verarbeitung einschränken (nicht löschen)\n• Recht auf\nWiderspruch: Verarbeitung stoppen\n• Recht auf\nDatenübertragbarkeit: Daten im maschinenlesbaren Format erhalten', url: '', hashtags: ['#DSGVO', '#Datenschutz', '#AP1']),
  CardModel(id: 'datenschutzKarten-003', question: 'Was ist der Unterschied zwischen Anonymisierung und Pseudonymisierung?', shortAnswer: 'Anonymisiert = kein Rückschluss auf Person möglich; Pseudonymisiert = mit Schlüssel rückverfolgbar', longAnswer: '• Anonymisierung: Personenbezug wird unwiderruflich entfernt\n→ Keine Verbindung zur Person mehr möglich\n→ Fällt nicht mehr unter DSGVO\nBeispiel: Statistiken ohne Namen\n• Pseudonymisierung: Direkte Identifikatoren durch Pseudonym ersetzt\n→ Mit Schlüssel kann Rückschluss gezogen werden\n→ Bleibt personenbezogenes Datum\nBeispiel: Kundennummer statt Name', url: '', hashtags: ['#DSGVO', '#Datenschutz', '#AP1']),
  CardModel(id: 'datenschutzKarten-004', question: 'Was sind personenbezogene Daten nach DSGVO?', shortAnswer: 'Alle Informationen, die eine natürliche Person direkt oder indirekt identifizierbar machen', longAnswer: 'Beispiele für personenbezogene\nDaten:\n• Name, Adresse, E-Mail, Telefon\n• IP-Adresse (in vielen Fällen)\n• Kundennummer (wenn Rückschluss möglich)\n• Foto, Video, Standortdaten\n• Gesundheitsdaten, biometrische Daten (besonders sensibel!)Besondere Kategorien (Art. 9): Gesundheit, Religionszugehörigkeit, politische Meinung, Ethnizität\n→ besonders geschützt\nNicht personenbezogen: Anonymisierte Statistiken', url: '', hashtags: ['#DSGVO', '#Datenschutz', '#AP1']),
];

// ── Verträge (3 Karten — 15x geprüft) ──
final List<CardModel> vertraegeKarten = [
  CardModel(id: 'vertraegeKarten-001', question: 'Was ist der Unterschied zwischen Werkvertrag und Dienstvertrag?', shortAnswer: 'Werkvertrag = Ergebnis geschuldet; Dienstvertrag = Leistung/Tätigkeit geschuldet', longAnswer: '• Werkvertrag (§631 BGB): Ein konkretes Ergebnis (Werk) wird geschuldet\n→ Abnahme notwendig, Gewährleistung 2 Jahre\nBeispiel: Softwareentwicklung, Webdesign-Projekt\n• Dienstvertrag (§611 BGB): Tätigkeit wird geschuldet, kein Erfolg garantiert\n→ Kein Abnahmeerfordernis, keine Gewährleistung\nBeispiel: IT-Beratung, SchulungWichtig für AP1: Aus dem Kontext erkennen, welcher Vertragstyp gemeint ist!', url: '', hashtags: ['#Recht', '#Vertraege', '#AP1']),
  CardModel(id: 'vertraegeKarten-002', question: 'Was sind SLAs (Service Level Agreements)?', shortAnswer: 'Vertraglich festgelegte Qualitätskennzahlen für IT-Dienstleistungen', longAnswer: 'Typische SLA-Inhalte:\n• Verfügbarkeit: z.B. 99,9% (entspricht max. 8,7 h Ausfall/Jahr)\n• Reaktionszeit: z.B. Incident muss innerhalb 4h bearbeitet sein\n• Wiederherstellungszeit (MTTR): z.B. System in 8h wiederhergestellt\n• Support-Zeiten: 24/7 oder 8×5\n• Pönale/Vertragsstrafen: Bei NichteinhaltungSLA-Verletzung\n→ Auftraggeber kann Schadensersatz fordern', url: '', hashtags: ['#Recht', '#Vertraege', '#AP1']),
  CardModel(id: 'vertraegeKarten-003', question: 'Was ist der Unterschied zwischen Gewährleistung und Garantie?', shortAnswer: 'Gewährleistung = gesetzlich (2 Jahre); Garantie = freiwillig vom Hersteller', longAnswer: '• Gewährleistung: Gesetzlich verankert (§433 BGB), 2 Jahre ab Übergabe\n→ Käufer kann Nachbesserung, Ersatz, Preisminderung oder Rücktritt fordern\n→ Gilt immer, kann nicht wegvertragen werden (B2C)\n• Garantie: Freiwillige Zusage des Herstellers/Händlers\n→ Inhalt, Dauer und Bedingungen frei wählbar\n→ Oft länger als Gewährleistung (z.B. 3 Jahre Herstellergarantie)', url: '', hashtags: ['#Recht', '#Vertraege', '#AP1']),
];

