// ── Methoden und Modelle (11 Karten — 11x geprüft) ──
final List<CardModel> methoden_und_modelleKarten = [
  CardModel(id: 'methoden_und_modelleKarten-001', question: 'Was ist ein Netzplan und welche Informationen enthält er?', shortAnswer: 'Grafische Darstellung der zeitlichen und logischen Abhängigkeiten von Projektaktivitäten', longAnswer: 'Ein Netzplan enthält für jeden\nVorgang:\n• FAZ\n– Frühester Anfangszeitpunkt\n• FEZ\n– Frühester Endzeitpunkt\n• SAZ\n– Spätester Anfangszeitpunkt\n• SEZ\n– Spätester Endzeitpunkt\n• D\n– Dauer\n• GP\n– Gesamtpuffer\n• FP\n– Freier Puffer\nVorteil: Kritischer Pfad und Pufferzeiten sind direkt ablesbar.', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
  CardModel(id: 'methoden_und_modelleKarten-002', question: 'Was ist der kritische Pfad in einem Netzplan?', shortAnswer: 'Der längste Weg durch den Netzplan – Vorgänge ohne Puffer, die die Gesamtdauer bestimmen', longAnswer: 'Eigenschaften des kritischen\nPfades:\n• Gesamtpuffer aller Vorgänge auf dem Pfad = 0\n• Bestimmt die minimale Projektdauer\n• Verzögerung eines Vorgangs\n→ direkte Verzögerung des GesamtprojektsFormel\nGesamtpuffer: GP = SAZ\n– FAZ = SEZ\n– FEZ\nVorgänge auf dem kritischen Pfad müssen besonders überwacht werden!', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
  CardModel(id: 'methoden_und_modelleKarten-003', question: 'Wie berechnet man FAZ und FEZ im Netzplan?', shortAnswer: 'FAZ des Nachfolgers = FEZ des Vorgängers; FEZ = FAZ + Dauer', longAnswer: 'Vorwärtsrechnung (berechnet FAZ und FEZ):\n• Erster\nVorgang: FAZ = 0\n• FEZ = FAZ + Dauer\n• FAZ Nachfolger = FEZ Vorgänger (bei mehreren\nVorgängern: Maximum)Rückwärtsrechnung (berechnet SAZ und SEZ):\n• Letzter\nVorgang: SEZ = FEZ (Projektende)\n• SAZ = SEZ\n– Dauer\n• SEZ Vorgänger = SAZ Nachfolger (bei mehreren: Minimum)', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
  CardModel(id: 'methoden_und_modelleKarten-004', question: 'Was ist der Unterschied zwischen Gesamtpuffer (GP) und Freiem Puffer (FP)?', shortAnswer: 'GP = max. Verzögerung ohne Projektende zu verschieben; FP = Verzögerung ohne Nachfolger zu beeinflussen', longAnswer: '• Gesamtpuffer (GP): GP = SAZ\n– FAZ = SEZ\n– FEZ\n→ Der Vorgang kann um GP Zeiteinheiten verschoben werden, ohne das Projektende zu verzögern\n• Freier Puffer (FP): FP = FAZ(Nachfolger) – FEZ(Vorgang)\n→ Verzögerung hat keine Auswirkung auf nachfolgende VorgängeBeim kritischen Pfad gilt: GP = 0 und FP = 0', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
  CardModel(id: 'methoden_und_modelleKarten-005', question: 'Was ist ein Gantt-Diagramm?', shortAnswer: 'Balkendiagramm zur Visualisierung des zeitlichen Ablaufs von Projektaktivitäten', longAnswer: 'Merkmale des Gantt-Diagramms:\n• Aktivitäten werden als Balken auf einer Zeitachse dargestellt\n• Parallelität von Vorgängen ist sofort erkennbar\n• Abhängigkeiten können mit Pfeilen dargestellt werden\n• Meilensteine als Rauten sichtbarUnterschied zum\nNetzplan:\n• Gantt = zeitliche Sicht (WANN)\n• Netzplan = logische + zeitliche Sicht (WANN + WARUM)', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
  CardModel(id: 'methoden_und_modelleKarten-006', question: 'Was ist der Unterschied zwischen Wasserfall- und Scrum-Modell?', shortAnswer: 'Wasserfall = sequenziell und geplant; Scrum = iterativ und agil', longAnswer: 'WasserfallScrumPhasen nacheinanderSprints (2\n– 4 Wochen)Anforderungen fixAnforderungen flexibelPlangetriebenWertegetriebenWenig KundenkontaktStändiger KundenkontaktGut bei klaren AnforderungenGut bei unklaren Anforderungen', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
  CardModel(id: 'methoden_und_modelleKarten-007', question: 'Was ist ein Kanban-Board und was bedeutet WIP-Limit?', shortAnswer: 'Visuelles Steuerungssystem für Arbeitsfluss; WIP = maximale Anzahl gleichzeitiger Aufgaben', longAnswer: 'Kanban-Prinzipien:\n• Spalten entsprechen Prozessschritten (z.B. To Do\n→ In Progress\n→ Done)\n• WIP-Limit (Work in Progress): Begrenzt die Anzahl gleichzeitiger Aufgaben pro Spalte\n• Pull statt\nPush: Aufgaben werden selbst gezogen, nicht zugeteilt\n• Visualisiert Engpässe (Bottlenecks)Vorteil: Verhindert Überlastung, macht Arbeitsfluss sichtbar.', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
  CardModel(id: 'methoden_und_modelleKarten-008', question: 'Was ist ein Projektstrukturplan (PSP)?', shortAnswer: 'Hierarchische Gliederung aller Projektaufgaben in plan- und kontrollierbare Arbeitspakete', longAnswer: 'Merkmale des PSP:\n• Statische Sicht (keine Zeitachse!)\n• Zerlegung des Gesamtprojekts von oben nach unten\n• Erstellt per Top-Down (deduktiv) oder Bottom-Up (induktiv) oder Yo-Yo (kombiniert)Unterschied zu Netzplan/Gantt: PSP zeigt WAS, nicht WANN!\nBasis für: Terminplanung, Kostenplanung, Ressourcenplanung', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
  CardModel(id: 'methoden_und_modelleKarten-009', question: 'Was sind die Scrum-Rollen und ihre Aufgaben?', shortAnswer: 'Product Owner, Scrum Master und Entwicklungsteam', longAnswer: '• Product\nOwner: Verantwortlich für den Product Backlog, priorisiert Anforderungen, vertritt Kundenwünsche\n• Scrum\nMaster: Moderiert, beseitigt Hindernisse (Impediments), schützt das Team, kein klassischer Vorgesetzter\n• Entwicklungsteam: Selbstorganisiert, cross-funktional, 3\n– 9 Personen, liefert potenziell auslieferbares InkrementSprint-Ereignisse: Sprint Planning, Daily Scrum, Sprint Review, Sprint Retrospektive', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
  CardModel(id: 'methoden_und_modelleKarten-010', question: 'Was ist ein Projektstrukturplan (PSP) nach funktionsorientierter Gliederung?', shortAnswer: 'Gliederung nach Funktionen/Abteilungen (z.B. Entwicklung, Test, Dokumentation)', longAnswer: 'Arten der PSP-Gliederung:\n• Funktionsorientiert: Nach Tätigkeiten/Disziplinen (Was wird getan?)\n• Objektorientiert: Nach Ergebnissen/Lieferobjekten (Was entsteht?)\n• Zeitorientiert: Nach Projektphasen (Wann?)\n• Mischform: Kombination, häufig in der Praxis', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
  CardModel(id: 'methoden_und_modelleKarten-011', question: 'Was ist der Unterschied zwischen Makrofeasibility und Mikrofeasibility?', shortAnswer: 'Machbarkeitsanalyse auf strategischer (Makro) vs. operativer (Mikro) Ebene', longAnswer: 'Dimensionen der\nMachbarkeitsanalyse:\n• Technisch: Ist die Umsetzung technisch möglich?\n• Organisatorisch: Können Prozesse angepasst werden?\n• Wirtschaftlich: Ist es rentabel? ROI positiv?\n• Zeitlich: Ist der Zeitplan realistisch?\n• Rechtlich: Gibt es rechtliche Hindernisse?Ergebnis: Go/No-Go-Entscheidung für das Projekt.', url: '', hashtags: ['#Methoden', '#Projektmanagement', '#AP1']),
];

